#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, Y, Z; scanf("%lld %lld %lld", &X, &Y, &Z);
        long long travel = Y / X;
        long long wait = (Z > travel) ? (Z - travel) : 0;
        printf("%lld", wait);
        if(T) printf("\n");
    }
    return 0;
}

